use std::io::{self, prelude::*};


#[allow(unused_must_use)]
fn solve<B: BufRead, W: Write>(mut scan: Scanner<B>, mut w: W) {
    let n = scan.token::<usize>();
    let m = scan.token::<usize>();

    let mut primes = [true; 51];

    primes[0] = false;
    primes[1] = false;

    for i in 2usize..=50 {
        for j in ((2*i)..=50).step_by(i) {
            primes[j] = false;
        }
    }

    let mut i = n;
    assert!(primes[i]);

    let mut ans = "NO";
    while i < 50 {
        i += 1;
        if primes[i] == true {
            if i == m {
                ans = "YES"
            }
            break;
        }
    }

    writeln!(w, "{}", ans);
}

fn main() {
    let stdin = io::stdin();
    let stdout = io::stdout();
    let reader = Scanner::new(stdin.lock());
    let writer = io::BufWriter::new(stdout.lock());
    solve(reader, writer);
}

